import{c as o,$ as n,Q as t,j as r,m as a,h as d,ax as i,n as l,o as h,S as c}from"./chunks/framework.C1Tv9fGx.js";const v=JSON.parse('{"title":"Why NLPM is built","description":"","frontmatter":{"title":"Why NLPM is built","outline":[2,3]},"headers":[],"relativePath":"why.md","filePath":"why.md","lastUpdated":1779698428000}'),p={name:"why.md"};function u(g,e,m,f,y,b){const s=n("Mermaid");return t(),r("div",null,[e[1]||(e[1]=a(`<h1 id="why-nlpm-is-built" tabindex="-1">Why NLPM is built <a class="header-anchor" href="#why-nlpm-is-built" aria-label="Permalink to &quot;Why NLPM is built&quot;">​</a></h1><p>NLPM exists because a 69,816-star plugin shipped four invisible skills, and no validator in the ecosystem was going to catch it.</p><p>That sentence is small enough to dismiss. The rest of this page argues why it shouldn&#39;t be.</p><h2 id="the-bug-class-that-keeps-shipping" tabindex="-1">The bug class that keeps shipping <a class="header-anchor" href="#the-bug-class-that-keeps-shipping" aria-label="Permalink to &quot;The bug class that keeps shipping&quot;">​</a></h2><p><code>mattpocock/skills</code> (69.8k stars, MIT-licensed, written by a TypeScript ecosystem figure with a reputation for rigorous tooling) shipped with 13 skills declared in <code>plugin.json</code> and 17 SKILL.md files on disk. The four extras — <code>git-guardrails-claude-code</code>, <code>setup-pre-commit</code>, <code>migrate-to-shoehorn</code>, <code>scaffold-exercises</code> — each had valid frontmatter and worked locally. None of them were reachable after <code>claude plugin install</code>.</p><p>The diff that finds this is mechanical:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.skills[]&#39; .claude-plugin/plugin.json </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;skills/*/*/SKILL.md&#39; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s|/SKILL.md||;s|^|./|&#39; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span></span></code></pre></div><p>Five seconds. No judgment. No model needed.</p><p>This isn&#39;t an isolated lapse. The same bug class has shipped in <code>safishamsi/graphify</code> (37k⭐), <code>kubesphere/kubesphere</code> (16k⭐), <code>tanweai/pua</code> (16.7k⭐), and <code>agent-sh/agnix</code> (5k⭐). The maintainers are not careless — they are using the tools that exist for the layer those tools cover. The bug ships because no tool covers <em>this</em> layer.</p><h2 id="what-the-ecosystem-already-has" tabindex="-1">What the ecosystem already has <a class="header-anchor" href="#what-the-ecosystem-already-has" aria-label="Permalink to &quot;What the ecosystem already has&quot;">​</a></h2><p>By 2026-05, there are at least eight SKILL.md / plugin-manifest validators in active development:</p><table tabindex="0"><thead><tr><th>Source</th><th>What it checks</th></tr></thead><tbody><tr><td><code>claude plugin validate</code> (Anthropic, built-in CLI)</td><td>Manifest JSON syntax + deprecation warnings</td></tr><tr><td><code>plugin-validator</code> agent (Anthropic)</td><td>Per-component frontmatter, manifest fields, security, MCP config</td></tr><tr><td><code>skills-ref</code> (Linux Foundation, Python + Rust)</td><td>Per-skill: frontmatter validity, <code>name == parent_dir</code></td></tr><tr><td><code>claude-plugin-validate</code> (situ2001, Rust)</td><td>Manifest schema, frontmatter, hooks JSON</td></tr><tr><td><code>agent-skill-linter</code> (William-Yeh)</td><td>Spec compliance, badges, LICENSE, auto-fix</td></tr><tr><td><code>skill-check</code> (thedaviddias)</td><td>Structure, body limits, description quality, 0–100 score</td></tr><tr><td><code>skill-validator</code> (agent-ecosystem)</td><td>Content density + pre-commit hooks</td></tr><tr><td><code>skill-linter</code> ×2 (majesticlabs, RHEcosystem)</td><td>Marketplace gate logic</td></tr></tbody></table><p>The validators concentrate at the <strong>single-artifact</strong> boundary: does <em>this</em> SKILL.md have a valid <code>name</code>? Does <em>this</em> <code>plugin.json</code> parse? At that layer, eight tools compete and any one of them catches what the others catch.</p><p>The validators avoid the <strong>cross-artifact</strong> boundary: does the array in <code>plugin.json</code> enumerate every SKILL.md on disk? Does every tool in <code>allowed-tools</code> have a call site? Do cross-references resolve?</p><p><code>/nlpm:check</code> is, by current research, the only validator that systematically checks this layer.</p><h2 id="why-the-gap-exists" tabindex="-1">Why the gap exists <a class="header-anchor" href="#why-the-gap-exists" aria-label="Permalink to &quot;Why the gap exists&quot;">​</a></h2><p>Five compounding factors keep the bug class shipping:</p><ol><li><strong>The right validator missing in canonical form.</strong> Manifest-vs-disk isn&#39;t in Anthropic&#39;s official <code>plugin-validator</code>. Authors who reach for &quot;the official tool&quot; don&#39;t get this check.</li><li><strong>Discovery is broken.</strong> Eight tools, no SEO winner, no GitHub Actions template that ships with <code>claude plugin init</code>. Authors don&#39;t know which tool to pick, so most pick none.</li><li><strong>The spec is young.</strong> Anthropic published Agent Skills on 2025-12-18. Five months is not enough time for collective practice to crystallize — TypeScript took about five years to settle on <code>tsc --noEmit</code> + ESLint + <code>tsconfig.json</code> as the canonical local validation stack.</li><li><strong>&quot;Works on my machine&quot; is the testing default.</strong> Authors develop in their own <code>.claude/</code> directory; the runtime walks the filesystem and finds the skill. The bug only surfaces on a fresh install of the published manifest — a code path the author rarely exercises.</li><li><strong>No install-time loud failure.</strong> <code>claude plugin install</code> succeeds with an incomplete manifest. Missing skills are silently invisible. There is no <code>ImportError</code>-equivalent that tells the author what they just published is broken.</li></ol><p>Every successful code ecosystem has at least one install-time or build-time gate that fails loudly on this class of inconsistency:</p><table tabindex="0"><thead><tr><th>Ecosystem</th><th>Forcing function</th></tr></thead><tbody><tr><td>TypeScript / Node</td><td>Missing <code>exports</code> → <code>Cannot find module</code> at runtime</td></tr><tr><td>Python</td><td>Missing <code>entry_points</code> → <code>pkg_resources.DistributionNotFound</code></td></tr><tr><td>Rust</td><td><code>cargo build</code> cross-checks <code>mod</code> against <code>src/</code></td></tr><tr><td>Ruby</td><td><code>gem build</code> rejects gemspecs referencing missing files</td></tr><tr><td>Go</td><td><code>go build</code> and <code>go vet</code> cross-check declared packages against disk</td></tr><tr><td><strong>Claude plugins</strong></td><td>None. Install succeeds with incomplete manifest.</td></tr></tbody></table><p>Plugin authoring doesn&#39;t have that gate yet. NLPM is one attempt to provide it.</p><h2 id="the-deeper-observation" tabindex="-1">The deeper observation <a class="header-anchor" href="#the-deeper-observation" aria-label="Permalink to &quot;The deeper observation&quot;">​</a></h2><p>Patching one missing check would be a small open-source contribution. NLPM is shaped around a bigger claim: <strong>natural-language programs are programs, and a program needs a vocabulary as much as it needs a syntax.</strong></p><p>A SKILL.md isn&#39;t prose. It is a declaration that an executor (Claude, Codex, another agent) will read and act on. When two skills name the same act with different verbs, when an agent says &quot;scan&quot; in one place and &quot;check&quot; three lines later, when a noun-verb pairing exists in one file and the inverted form in another — these aren&#39;t stylistic preferences. They are the NL equivalent of redeclaring a function with a different signature and hoping the linker figures it out.</p><p>This led to the six vocabulary principles (P1–P6)<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>, drawn from OntoClean (Guarino &amp; Welty), Domain-Driven Design (Evans), ISO 25964 / ANSI-NISO Z39.19 warrant theory, and BPMN / Event Storming (Brandolini):</p>`,25)),(t(),d(c,null,{default:i(()=>[h(s,{id:"mermaid-231",class:"mermaid-diagram",graph:"flowchart%20TD%0A%20%20P2%5B%22P2%20%E2%80%94%20nouns%20rigid%3Cbr%2F%3Everbs%20state-changing%22%5D%20--%3E%20P3%5B%22P3%20%E2%80%94%20verb%20only%3Cbr%2F%3Eif%20it%20gates%20or%20produces%22%5D%0A%20%20P3%20--%3E%20P1%5B%22P1%20%E2%80%94%20one%20term%20per%3Cbr%2F%3Eidentity%2C%20within%20scope%22%5D%0A%20%20P1%20--%3E%20P4%5B%22P4%20%E2%80%94%20vocabulary%3Cbr%2F%3Eclosed%20under%20operations%22%5D%0A%20%20P4%20--%3E%20P5%5B%22P5%20%E2%80%94%20no%20unnamed%3Cbr%2F%3Ejudgment%22%5D%0A%20%20P5%20--%3E%20P6%5B%22P6%20%E2%80%94%20warrant%3Cbr%2F%3Ebefore%20entry%22%5D%0A%0A%20%20classDef%20p%20fill%3A%23d5e0ff%2Cstroke%3A%232b5fff%2Ccolor%3A%231d2433%0A%20%20class%20P1%2CP2%2CP3%2CP4%2CP5%2CP6%20p%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p>The arrows are precedence — P2 takes precedence over P3, P3 over P1, and so on. The order matters. P6 (warrant) is an entry check, not a veto over terms that satisfy the higher principles, which is why deferred terms in NLPM&#39;s own registry remain deferred rather than rejected.</p><p>These principles power R51 — NLPM&#39;s opt-in vocabulary-drift rule — and the registry-free <code>/nlpm:vocab-drift</code> scan that ships alongside it.</p><h2 id="what-nlpm-is-framed-by-the-gap" tabindex="-1">What NLPM is, framed by the gap <a class="header-anchor" href="#what-nlpm-is-framed-by-the-gap" aria-label="Permalink to &quot;What NLPM is, framed by the gap&quot;">​</a></h2><p>The shape of the tool follows from the two observations above.</p><table tabindex="0"><thead><tr><th>Component</th><th>Why it exists</th></tr></thead><tbody><tr><td><code>/nlpm:check</code></td><td>Cross-artifact validation — the layer no other tool covers</td></tr><tr><td><code>/nlpm:score</code> (51 rules, 100-point)</td><td>Quality scoring grounded in primary-source citations, not house style</td></tr><tr><td><code>/nlpm:vocab-drift</code> + R51</td><td>Vocabulary discipline; opt-in by design</td></tr><tr><td><code>bin/nlpm-check</code> (stdlib-only Python)</td><td>Pre-commit / CI gate that runs without Claude Code</td></tr><tr><td>Auditor pipeline</td><td>Continuous corpus building — the rules get refined by contact with real plugins, not by speculation</td></tr><tr><td>Case studies + exemplars</td><td>Evidence trail; every rule cites real-world examples</td></tr></tbody></table><p>The two pipelines (local for authors, auditor for the corpus) share one rulebook. Findings from the auditor feed <code>rule-health.py</code>. Rules that generate noise get refined. Rules with strong real-world warrant become exemplars that cite back into the rulebook. The loop is closed, and only one step in it (rule refinement) is allowed to mutate the rulebook — and only through a human-reviewed PR.</p><h2 id="the-corpus-as-of-today" tabindex="-1">The corpus, as of today <a class="header-anchor" href="#the-corpus-as-of-today" aria-label="Permalink to &quot;The corpus, as of today&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Count</th></tr></thead><tbody><tr><td>Repos audited</td><td>210</td></tr><tr><td>Case studies written</td><td>28</td></tr><tr><td>Exemplars cited in the rulebook</td><td>62</td></tr><tr><td>Rules in the rulebook</td><td>51</td></tr><tr><td>Vocabulary principles</td><td>6</td></tr><tr><td>NLPM&#39;s own self-audit score</td><td>100 / 100</td></tr></tbody></table><p>The corpus is what makes the rules trustable. A rule with no examples in the wild is a hypothesis; a rule with a dozen exemplars is a codified observation. The auditor pipeline is the mechanism that converts the first into the second.</p><h2 id="the-wager" tabindex="-1">The wager <a class="header-anchor" href="#the-wager" aria-label="Permalink to &quot;The wager&quot;">​</a></h2><p>Three things could falsify the whole project:</p><ol><li><strong>Anthropic adds manifest-vs-disk to the official <code>plugin-validator</code>.</strong> This would erase NLPM&#39;s headline differentiation overnight. Probability: moderate; timeline: unknown. The mitigation is that the audit corpus and the rule-health feedback loop are the durable asset, not the single check.</li><li><strong>The ecosystem converges on one third-party validator.</strong> Unlikely in the 5-month timeframe but possible by 2027. Today&#39;s fragmentation is the opportunity.</li><li><strong>Authors don&#39;t care.</strong> If the bug class doesn&#39;t bother maintainers enough to install a hook, adoption stays at zero.</li></ol><p>Joint probability of meaningful adoption: somewhere in the 20–35% range, by honest accounting. The asymmetry is the case for shipping anyway. Cost of being wrong: a couple of templates and a Python script. Cost of being right and nobody else covering the gap: thousands of plugins keep shipping with invisible bugs.</p><p>NLPM is the bet that the gap is worth filling, that vocabulary discipline is worth naming, and that a corpus of real audits will outlast any single rule.</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>The principles document lives at <a href="https://github.com/xiaolai/nlpm/blob/main/analysis/vocabulary-design-principles.md" target="_blank" rel="noreferrer"><code>analysis/vocabulary-design-principles.md</code></a> in the repository, with the full precedence rationale and the OntoClean / DDD / ISO 25964 / BPMN derivation. The shorter web-facing version is at <a href="/_pr/292/reference/principles">/reference/principles</a>. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',16))])}const w=o(p,[["render",u]]);export{v as __pageData,w as default};
